import os
import time
import json
import hashlib
from datetime import datetime, timedelta
from functools import wraps
from flask import request, current_app

class DiskCache:
    def __init__(self, cache_dir='cache', default_ttl_seconds=3600):
        self.cache_dir = cache_dir
        self.default_ttl_seconds = default_ttl_seconds
        os.makedirs(self.cache_dir, exist_ok=True)

    def _get_filepath(self, key):
        filename = hashlib.md5(key.encode('utf-8')).hexdigest() + '.json'
        return os.path.join(self.cache_dir, filename)

    def set(self, key, value, ttl_seconds=None):
        if ttl_seconds is None:
            ttl_seconds = self.default_ttl_seconds

        expires_at = datetime.now() + timedelta(seconds=ttl_seconds)
        data = {
            'value': value,
            'expires_at': expires_at.isoformat()
        }
        filepath = self._get_filepath(key)
        try:
            with open(filepath, 'w') as f:
                json.dump(data, f)
        except Exception as e:
            current_app.logger.error(f"Error writing to cache file {filepath}: {e}")

    def get(self, key):
        filepath = self._get_filepath(key)
        if not os.path.exists(filepath):
            return None

        try:
            with open(filepath, 'r') as f:
                data = json.load(f)

            expires_at = datetime.fromisoformat(data['expires_at'])
            if datetime.now() < expires_at:
                return data['value']
            else:
                # Cache expired
                self.delete(key)
                return None
        except (json.JSONDecodeError, KeyError, ValueError) as e:
            current_app.logger.warning(f"Error reading or parsing cache file {filepath}: {e}. Deleting corrupted entry.")
            self.delete(key)
            return None
        except Exception as e:
            current_app.logger.error(f"Unexpected error getting from cache file {filepath}: {e}")
            return None

    def delete(self, key):
        filepath = self._get_filepath(key)
        if os.path.exists(filepath):
            try:
                os.remove(filepath)
            except Exception as e:
                current_app.logger.error(f"Error deleting cache file {filepath}: {e}")

    def clear(self):
        for filename in os.listdir(self.cache_dir):
            filepath = os.path.join(self.cache_dir, filename)
            if os.path.isfile(filepath):
                try:
                    os.remove(filepath)
                except Exception as e:
                    current_app.logger.error(f"Error clearing cache file {filepath}: {e}")

def cached_api_response(cache_instance, ttl_seconds=None):
    def decorator(f):
        @wraps(f)
        def decorated_function(*args, **kwargs):
            # Generate a cache key based on the function name, args, kwargs, and request path/query
            # For API responses, we usually care about the request method, path, and query parameters
            # You might want to customize this key generation for more specific needs
            
            # Use request.full_path for a robust key including query params
            # Ensure current_app exists before using it (e.g., inside a Flask app context)
            if current_app:
                cache_key_components = [
                    f.__name__,
                    request.method,
                    request.full_path,
                    json.dumps(request.get_json(silent=True) if request.is_json else request.form.to_dict(), sort_keys=True) if request.method in ['POST', 'PUT'] else ''
                ]
            else: # Fallback for testing outside a request context
                cache_key_components = [
                    f.__name__,
                    json.dumps(args, sort_keys=True),
                    json.dumps(kwargs, sort_keys=True)
                ]
            
            cache_key = hashlib.md5("".join(cache_key_components).encode('utf-8')).hexdigest()

            cached_data = cache_instance.get(cache_key)
            if cached_data is not None:
                current_app.logger.info(f"Cache hit for {cache_key}")
                return cached_data # Assume the cached_data is already a Flask response or response data

            current_app.logger.info(f"Cache miss for {cache_key}. Calling API.")
            result = f(*args, **kwargs) # Call the original function to get the API response

            # If the result is a Flask Response object, extract its JSON content for caching
            # If it's already a dictionary/list, cache it directly
            data_to_cache = result
            if hasattr(result, 'get_json') and callable(result.get_json):
                data_to_cache = result.get_json()
            elif hasattr(result, 'json') and result.json is not None:
                data_to_cache = result.json

            cache_instance.set(cache_key, data_to_cache, ttl_seconds=ttl_seconds)
            return result
        return decorated_function
    return decorator


